350	// validates a KubeletConfig and returns an error if invalid
351	// nolint:gocyclo
352	func validateUserKubeletConfig(cfg *mcfgv1.KubeletConfig) error {
353		if cfg.Spec.LogLevel != nil && (*cfg.Spec.LogLevel < 0 || *cfg.Spec.LogLevel > 10) {
354			return fmt.Errorf("KubeletConfig's LogLevel is not valid [0,10]: %d", *cfg.Spec.LogLevel)
355		}
356		if cfg.Spec.KubeletConfig == nil || cfg.Spec.KubeletConfig.Raw == nil {
357			return nil
358		}
359		kcDecoded, err := DecodeKubeletConfig(cfg.Spec.KubeletConfig.Raw)
360		if err != nil {
361			return fmt.Errorf("KubeletConfig could not be unmarshalled, err: %w", err)
362		}
363	
364		// Check all the fields a user cannot set within the KubeletConfig CR.
365		// If a user were to set these values, the system may become unrecoverable
366		// (ie: not recover after a reboot).
367		// Therefore, if the KubeletConfig CR instance contains a non-zero or non-empty value
368		// for one of the following fields, the MCC will not apply the CR and error out instead.
369		if kcDecoded.CgroupDriver != "" {
370			return fmt.Errorf("KubeletConfiguration: cgroupDriver is not allowed to be set, but contains: %s", kcDecoded.CgroupDriver)
371		}
372		if len(kcDecoded.ClusterDNS) > 0 {
373			return fmt.Errorf("KubeletConfiguration: clusterDNS is not allowed to be set, but contains: %s", kcDecoded.ClusterDNS)
374		}
375		if kcDecoded.ClusterDomain != "" {
376			return fmt.Errorf("KubeletConfiguration: clusterDomain is not allowed to be set, but contains: %s", kcDecoded.ClusterDomain)
377		}
378		if len(kcDecoded.FeatureGates) > 0 {
379			return fmt.Errorf("KubeletConfiguration: featureGates is not allowed to be set, but contains: %v", kcDecoded.FeatureGates)
380		}
381		if kcDecoded.StaticPodPath != "" {
382			return fmt.Errorf("KubeletConfiguration: staticPodPath is not allowed to be set, but contains: %s", kcDecoded.StaticPodPath)
383		}
384		if kcDecoded.FailSwapOn != nil {
385			return fmt.Errorf("KubeletConfiguration: failSwapOn is not allowed to be set, but contains: %v", *kcDecoded.FailSwapOn)
386		}
387		if kcDecoded.MemorySwap.SwapBehavior != "" {
388			return fmt.Errorf("KubeletConfiguration: swapBehavior is not allowed to be set, but contains: %s", kcDecoded.MemorySwap.SwapBehavior)
389		}
390		if kcDecoded.SystemReserved != nil && len(kcDecoded.SystemReserved) > 0 &&
391			cfg.Spec.AutoSizingReserved != nil && *cfg.Spec.AutoSizingReserved {
392			return fmt.Errorf("KubeletConfiguration: autoSizingReserved and systemdReserved cannot be set together")
393		}
394		// Validate that systemReservedCgroup matches systemCgroups if both are set
395		if kcDecoded.SystemReservedCgroup != "" && kcDecoded.SystemCgroups != "" && kcDecoded.SystemReservedCgroup != kcDecoded.SystemCgroups {
396			return fmt.Errorf("KubeletConfiguration: systemReservedCgroup (%s) must match systemCgroups (%s)", kcDecoded.SystemReservedCgroup, kcDecoded.SystemCgroups)
397		}
398		return nil
399	}
