1477	// GetEffectiveOSImageStreamName returns the effective osImageStream name for a pool,
1478	// taking inheritance from the worker pool into account for custom pools.
1479	// Returns:
1480	// - The pool's explicit osImageStream.Name if set
1481	// - For custom pools: the worker pool's osImageStream.Name if the custom pool has none
1482	// - Empty string (which will resolve to the default stream)
1483	//
1484	// This function can return an error if the worker pool cannot be fetched.
1485	func GetEffectiveOSImageStreamName(pool *mcfgv1.MachineConfigPool, mcpLister mcfglistersv1.MachineConfigPoolLister) (string, error) {
1486		// If the pool explicitly sets an osImageStream, use it
1487		if pool.Spec.OSImageStream.Name != "" {
1488			return pool.Spec.OSImageStream.Name, nil
1489		}
1490	
1491		// Only custom pools inherit from worker; standard pools use default directly
1492		if !IsCustomPool(pool) {
1493			return "", nil
1494		}
1495	
1496		// For custom pools with no explicit stream, try to inherit from worker
1497		workerPool, err := mcpLister.Get(MachineConfigPoolWorker)
1498		if err != nil {
1499			// If worker pool doesn't exist or can't be fetched, use default stream
1500			if !kerr.IsNotFound(err) {
1501				return "", fmt.Errorf("failed to get worker pool for osImageStream inheritance: %w", err)
1502			}
1503			return "", nil
1504		}
1505	
1506		// Return worker pool's stream (which may be empty, indicating default)
1507		return workerPool.Spec.OSImageStream.Name, nil
1508	}
