201		kcListAll, err := client.MachineconfigurationV1().KubeletConfigs().List(context.TODO(), metav1.ListOptions{})
202		if err != nil {
203			return "", fmt.Errorf("error listing kubelet configs: %w", err)
204		}
205	
206		// If there is no kubelet config in the list, return the default MC name with no suffix
207		if kcListAll == nil || len(kcListAll.Items) == 0 {
208			return ctrlcommon.GetManagedKey(pool, client, managedKubeletConfigKeyPrefix, "kubelet", getManagedKubeletConfigKeyDeprecated(pool))
209		}
210	
211		var kcList []mcfgv1.KubeletConfig
212		for _, kc := range kcListAll.Items {
213			selector, err := metav1.LabelSelectorAsSelector(kc.Spec.MachineConfigPoolSelector)
214			if err != nil {
215				return "", fmt.Errorf("invalid label selector: %w", err)
216			}
217			if selector.Empty() || !selector.Matches(labels.Set(pool.Labels)) {
218				continue
219			}
220			kcList = append(kcList, kc)
221		}
222	
223		for _, kc := range kcList {
224			if kc.Name != cfg.Name {
225				continue
226			}
227			val, ok := kc.GetAnnotations()[ctrlcommon.MCNameSuffixAnnotationKey]
228			if !ok {
229				break
230			}
231			// if an MC name suffix exists, append it to the default MC name and return that as this kubelet config exists and
232			// we are probably doing an update action on it
233			if val != "" {
234				return fmt.Sprintf("%s-%s-generated-kubelet-%s", managedKubeletConfigKeyPrefix, pool.Name, val), nil
235			}
236			// if the suffix val is "", mc name should not suffixed the cfg to be updated is the first kubelet config has been created
237			return ctrlcommon.GetManagedKey(pool, client, managedKubeletConfigKeyPrefix, "kubelet", getManagedKubeletConfigKeyDeprecated(pool))
238		}
239	
240		// If we are here, this means that
241		// 1. a new kubelet config was created, so we have to calculate the suffix value for its MC name
242		// 2. or this is an existing kubeletconfig did not get ctrlcommon.MCNameSuffixAnnotationKey set, so we have to set the MCNameSuffixAnnotationKey to the machineconfig suffix it was rendered to, assume for existing kubeletconfig, cfg.Finalizers with the largest suffix is the machine config the kcfg was rendered to
243		// if the kubelet config is the only one in the list, mc name should not suffixed since cfg is the first kubelet config to be created
244		if len(kcList) == 1 {
245			return ctrlcommon.GetManagedKey(pool, client, managedKubeletConfigKeyPrefix, "kubelet", getManagedKubeletConfigKeyDeprecated(pool))
246		}
247		// if cfg is not a newly created kubeletconfig and did not get ctrlcommon.MCNameSuffixAnnotationKey
248		// but has been rendered to a machineconfig, its len(cfg.Finalizers) > 0
249		if notLatestKubeletConfigInPool(kcList, cfg) {
250			finalizers := cfg.GetFinalizers()
251			kubeletMCPrefix := fmt.Sprintf("99-%s-generated-kubelet", pool.Name)
252			latestFinalizerIdx := -1
253			maxFinalizerSuffix := -1
254			for i, f := range finalizers {
255				// skip the finalizer:
256				// the finalizer is not a machineconfig
257				// the finalizer is not generated by kubeletconfig controller of this pool
258				if _, err := client.MachineconfigurationV1().MachineConfigs().Get(context.TODO(), f, metav1.GetOptions{}); err != nil {
259					klog.Infof("skipping error: %v", fmt.Errorf("kubeletconfig %s has invalid finalizer: %s", cfg.Name, f))
260					continue
261				}
262				if !strings.HasPrefix(f, kubeletMCPrefix) {
263					continue
264				}
265				arr := strings.Split(f, "-")
266				suffix, err := strconv.Atoi(arr[len(arr)-1])
267				// if the finalizer does not end with a number, make sure it is in the format 99-<poolname>-generated-kubelet
268				// otherwise, the kcfg contains invalid finalizer, do not generate managedKey from finalizers
269				if err != nil {
270					key, err := ctrlcommon.GetManagedKey(pool, nil, managedKubeletConfigKeyPrefix, "kubelet", getManagedKubeletConfigKeyDeprecated(pool))
271					if err != nil {
272						klog.Infof("skipping error: %v", fmt.Errorf("error generating managedKey for suffix %s: %w", key, err))
273						continue
274					}
275					if f != key {
276						klog.Infof("skipping error: %v", fmt.Errorf("finalizer format does not match the managedKubeletConfigKey: %s, want: %s", f, key))
277						continue
278					}
279					// if the suffix is not a number, f is 99-<poolname>-generated-kubelet
280					suffix = 0
281				}
282				if suffix > maxFinalizerSuffix {
283					maxFinalizerSuffix = suffix
284					latestFinalizerIdx = i
285				}
286			}
287	
288			if latestFinalizerIdx != -1 {
289				klog.Infof("return kubeletconfig managedKey from finalizers %s", finalizers[latestFinalizerIdx])
290				return finalizers[latestFinalizerIdx], nil
291			}
292			klog.Infof("skipping error generating managedKey for existing kubeletconfig %s from finalizers", cfg.Name)
293		}
294	
295		suffixNum := 0
296		// Go through the list of kubelet config objects created and get the max suffix value currently created
297		for _, item := range kcList {
298			val, ok := item.GetAnnotations()[ctrlcommon.MCNameSuffixAnnotationKey]
299			if ok && val != "" {
300				// Convert the suffix value to int so we can look through the list and grab the max suffix created so far
301				intVal, err := strconv.Atoi(val)
302				if err != nil {
303					return "", fmt.Errorf("error converting %s to int: %w", val, err)
304				}
305				if intVal > suffixNum {
306					suffixNum = intVal
307				}
308			}
309		}
310	
311		// The max suffix value that we can go till with this logic is 9 - this means that a user can create up to 10 different kubelet config CRs.
312		// However, if there is a kc-1 mapping to mc-1 and kc-2 mapping to mc-2 and the user deletes kc-1, it will delete mc-1 but
313		// then if the user creates a kc-new it will map to mc-3. This is what we want as the latest kubelet config created should be higher in priority
314		// so that those changes can be rolled out to the nodes. But users will have to be mindful of how many kubelet config CRs they create. Don't think
315		// anyone should ever have the need to create 10 when they can simply update an existing kubelet config unless it is to apply to another pool.
316		if suffixNum+1 > ctrlcommon.MaxMCNameSuffix {
317			return "", fmt.Errorf("max number of supported kubelet config (10) has been reached. Please delete old kubelet configs before retrying")
318		}
319		// Return the default MC name with the suffixNum+1 value appended to it
320		return fmt.Sprintf("%s-%s-generated-kubelet-%s", managedKubeletConfigKeyPrefix, pool.Name, strconv.Itoa(suffixNum+1)), nil
321	}
